import{_ as t,c as o,o as s,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.49: Fix Session Freeze, Add Haskell Formatting","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.49.md","filePath":"en/changelog/v1.1.49.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.49.md"};function r(l,i,d,h,c,p){return s(),o("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-49-fix-session-freeze-add-haskell-formatting" tabindex="-1">v1.1.49: Fix Session Freeze, Add Haskell Formatting <a class="header-anchor" href="#v1-1-49-fix-session-freeze-add-haskell-formatting" aria-label="Permalink to “v1.1.49: Fix Session Freeze, Add Haskell Formatting”">​</a></h1><p><strong>Release Date</strong>: February 3, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update fixes multiple critical issues including session freeze and file status calculation errors, adds Haskell code formatting support, and significantly improves desktop interaction experience.</p><hr><h2 id="bug-fix-session-freeze-issue" tabindex="-1">Bug Fix: Session Freeze Issue <a class="header-anchor" href="#bug-fix-session-freeze-issue" aria-label="Permalink to “Bug Fix: Session Freeze Issue”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When a session encountered an error, the status would get stuck in error state, preventing new sessions from starting.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed session state management. New sessions can start normally after errors. OpenCode no longer freezes.</p><hr><h2 id="new-feature-haskell-code-formatting" tabindex="-1">New Feature: Haskell Code Formatting <a class="header-anchor" href="#new-feature-haskell-code-formatting" aria-label="Permalink to “New Feature: Haskell Code Formatting”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added Ormolu code formatter support for formatting Haskell code.</p><h3 id="what-is-ormolu" tabindex="-1">What is Ormolu? <a class="header-anchor" href="#what-is-ormolu" aria-label="Permalink to “What is Ormolu?”">​</a></h3><p>Ormolu is a Haskell code formatting tool, similar to Prettier for JavaScript, that can automatically unify code style.</p><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><p>When a project contains Haskell code, OpenCode will automatically use Ormolu for formatting.</p><hr><h2 id="new-feature-custom-mdns-domain" tabindex="-1">New Feature: Custom mDNS Domain <a class="header-anchor" href="#new-feature-custom-mdns-domain" aria-label="Permalink to “New Feature: Custom mDNS Domain”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added <code>--mdns-domain</code> flag to customize mDNS hostname.</p><h3 id="what-s-it-for" tabindex="-1">What&#39;s it for? <a class="header-anchor" href="#what-s-it-for" aria-label="Permalink to “What&#39;s it for?”">​</a></h3><p>When accessing via LAN, you can customize a more friendly domain name.</p><h3 id="how-to-use-1" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to use?”">​</a></h3>',26),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode --mdns-domain mydevice.local")])],-1),a('<hr><h2 id="improvement-desktop-interaction-experience" tabindex="-1">Improvement: Desktop Interaction Experience <a class="header-anchor" href="#improvement-desktop-interaction-experience" aria-label="Permalink to “Improvement: Desktop Interaction Experience”">​</a></h2><h3 id="project-search" tabindex="-1">Project Search <a class="header-anchor" href="#project-search" aria-label="Permalink to “Project Search”">​</a></h3><p>Now you can search projects on desktop to quickly find the project you want to open.</p><h3 id="session-navigation" tabindex="-1">Session Navigation <a class="header-anchor" href="#session-navigation" aria-label="Permalink to “Session Navigation”">​</a></h3><p>Added keyboard shortcuts to switch between unread sessions.</p><h3 id="tab-close-shortcut" tabindex="-1">Tab Close Shortcut <a class="header-anchor" href="#tab-close-shortcut" aria-label="Permalink to “Tab Close Shortcut”">​</a></h3><p>Added shortcut for closing tabs.</p><h3 id="responsive-design" tabindex="-1">Responsive Design <a class="header-anchor" href="#responsive-design" aria-label="Permalink to “Responsive Design”">​</a></h3><p>Added breakpoints for optimized large screen layout.</p><hr><h2 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to “Bug Fixes”">​</a></h2><h3 id="file-status-calculation" tabindex="-1">File Status Calculation <a class="header-anchor" href="#file-status-calculation" aria-label="Permalink to “File Status Calculation”">​</a></h3><p>Added and deleted files now correctly calculate status.</p><h3 id="openai-session-title-generation" tabindex="-1">OpenAI Session Title Generation <a class="header-anchor" href="#openai-session-title-generation" aria-label="Permalink to “OpenAI Session Title Generation”">​</a></h3><p>Fixed session title generation issue when using OpenAI models.</p><h3 id="task-status-display" tabindex="-1">Task Status Display <a class="header-anchor" href="#task-status-display" aria-label="Permalink to “Task Status Display”">​</a></h3><p>Fixed task status not showing current tool status.</p><h3 id="copilot-provider" tabindex="-1">Copilot Provider <a class="header-anchor" href="#copilot-provider" aria-label="Permalink to “Copilot Provider”">​</a></h3><p>Fixed Copilot provider system message content conversion issue.</p><h3 id="agent-variable-scope" tabindex="-1">Agent Variable Scope <a class="header-anchor" href="#agent-variable-scope" aria-label="Permalink to “Agent Variable Scope”">​</a></h3><p>Fixed agent variant not properly scoped to model.</p><h3 id="mention-hidden-files" tabindex="-1">@ Mention Hidden Files <a class="header-anchor" href="#mention-hidden-files" aria-label="Permalink to “@ Mention Hidden Files”">​</a></h3><p>Fixed issue where folders and files starting with <code>.</code> couldn&#39;t be mentioned with @.</p><h3 id="windows-pty-encoding" tabindex="-1">Windows PTY Encoding <a class="header-anchor" href="#windows-pty-encoding" aria-label="Permalink to “Windows PTY Encoding”">​</a></h3><p>Added UTF-8 encoding defaults for Windows PTY.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Experiencing session freeze</td><td>✅ Highly recommended</td></tr><tr><td>Using Haskell</td><td>✅ Recommended upgrade</td></tr><tr><td>Desktop users</td><td>✅ Recommended upgrade</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',30),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert pull request that was mistakenly merged</li><li>Add --mdns-domain flag to customize mDNS hostname (@luiz290788)</li><li>Added and deleted file status now correctly calculated in app</li><li>Add User-Agent header for GitLab AI Gateway requests (@vglafirov)</li><li>Add Ormolu code formatter for Haskell (@mimi1vx)</li><li>Use OpenTUI OSC52 clipboard implementation</li><li>Convert system message content to string for Copilot provider (@jogi47)</li><li>Give OPENCODE_CONFIG_CONTENT proper priority for setting config based on docs (@OpeOginni)</li><li>Fixed session title generation with OpenAI models (@oomathias)</li><li>Simplify directory tree output for prompts</li><li>Fix task status to show current tool state from message store</li><li>Allow starting new sessions after errors by fixing stuck session status</li><li>Adjust resolve parts to properly order tool calls when messages contain multiple @ references</li><li>Hide badge for builtin slash commands</li><li>Add workspace tests to the app (@neriousy)</li><li>Send custom agent prompts as developer messages instead of user messages when using Codex subscriptions</li><li>Fixed variant logic for Anthropic models through OpenAI compatibility endpoint</li><li>Add prompt caching support for Claude Opus on AWS Bedrock (@rgodha24)</li><li>Scope agent variant to model (@neavo)</li><li>Prevent duplicate AGENTS.md injection when reading instruction files (@code-yeongyu)</li><li>OpenCode no longer hangs when using client.app.log() during initialization (@desmondsow)</li><li>Remove outer backtick wrapper in session transcript tool formatting (@zerone0x)</li><li>Allow user plugins to override built-in auth plugins (@JosXa)</li><li>Binary file handling in file view (@alexyaroshuk)</li><li>Ensure switching Anthropic models mid-conversation works without errors and fix reasoning opaque not being picked up for Gemini models</li><li>Fix issue where folders and files starting with &quot;.&quot; could not be mentioned with @</li><li>Show actual retry error message instead of generic error message</li><li>Use process.env directly for runtime environment mutations in provider (@jerome-benoit)</li><li>Add reasoning variants support for SAP AI Core (@jerome-benoit)</li><li>Add UTF-8 encoding defaults for Windows PTY (@01luyicheng)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Respect terminal transparency in system theme (@pablopunk)</li><li>Truncate session title in exit banner to prevent display overflow</li><li>Show exit message banner in TUI</li><li>Add spinner animation for Task tool</li><li>Correct pluralization of match count in grep and glob tools (@adamjhf)</li><li>Remove extra padding between search and results in dialog-select</li><li>Add UI for skill tool in session view</li><li>Conditionally render bash tool output in TUI</li><li>Add skill dialog for selecting and inserting skills</li><li>Enable password authentication for remote session attachment</li><li>Fix documentation issues (@lailoo)</li><li>Revert skill slash commands feature</li><li>Add skill slash commands to the app</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix prompt input overflow issue in app (@neriousy)</li><li>Sidebar losing projects on collapse has been fixed</li><li>Add workspace toggle command to command palette and prompt input (@alexyaroshuk)</li><li>Search through sessions</li><li>Standardize icon sizes in the application</li><li>Navigate to last project on open</li><li>User messages not rendering consistently</li><li>Add project context menu on right-click</li><li>Open project search in app (@neriousy)</li><li>Add tab close keybind to app (@ProdigyRahul)</li><li>Enhance responsive design with additional breakpoints for larger screen layout adjustments (@OpeOginni)</li><li>Add keyboard shortcuts for navigating between unread sessions (@Brendonovich)</li><li>Fix Rust build and bindings formatting in desktop application (@Brendonovich)</li><li>Remove unnecessary setTimeout in desktop app (@Brendonovich)</li><li>Throttle window state persistence in desktop application (@Brendonovich)</li><li>Integrate tauri-specta for desktop application (@Brendonovich)</li><li>Keep macOS titlebar stable under zoom (@Brendonovich)</li><li>Kill zombie server process on startup timeout (@heyitsmohdd)</li><li>Show skill and MCP badges for slash commands</li><li>Use static language names in Thai localization (@alexyaroshuk)</li><li>Add tests for general settings, shortcuts, providers and status popover (@neriousy)</li><li>Fixed session header &#39;share&#39; button to hug content (@alexyaroshuk)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=t(n,[["render",r]]);export{m as __pageData,g as default};
